mapper.select:
SELECT EMP_ID, EMP_NAME, DEPT_CODE, POSITION, HIRE_DATE, SALARY, GENDER, MARRIED, SKILL, HOBBY, MEMO
	FROM tbl_employees

	WHERE DEPT_CODE = #{sDeptCode}

SELECT EMP_ID, EMP_NAME, DEPT_CODE, POSITION, HIRE_DATE, SALARY, GENDER, MARRIED, SKILL, HOBBY, MEMO FROM tbl_employees
AND DEPT_CODE = #{sDeptCode}
AND EMP_NAME LIKE CONCAT('%',#{searchEmpName}, '%')

SELECT EMP_ID, EMP_NAME, DEPT_CODE, POSITION, HIRE_DATE, SALARY, GENDER, MARRIED, SKILL, HOBBY, MEMO FROM tbl_employees
AND DEPT_CODE = #{SRC_DEPT_CODE}
AND EMP_NAME LIKE CONCAT('%',#{SRC_EMP_NAME}, '%')

SELECT DET_CODE AS CODE, DET_NAME AS NAME
	FROM tbl_common_code
WHERE MST_CODE = #{_parameter}

mapper.update:
UPDATE tbl_employees
	SET EMP_ID = #{EMP_ID}
		 , EMP_NAME = #{EMP_NAME}
		 , DEPT_CODE = #{DEPT_CODE}
		 , POSITION = #{POSITION}
		 , HIRE_DATE = #{HIRE_DATE}
		 , SALARY = #{SALARY}
		 , GENDER = #{GENDER}
		 , MARRIED = #{MARRIED}
		 , SKILL = #{SKILL}
		 , HOBBY = #{HOBBY}
		 , MEMO = #{MEMO}
WHERE EMP_ID = #{DataSetSavedData.EMP_ID}
